#!/usr/bin/env python3
import base64, gzip, os, subprocess, time

FILES = {
    'server.js': '',
    'db.js': '',
    'package.json': 'H4sIAG/XJmoC/02PTQ7CIBBG9z0FYa2kJXXjBYwrm7g3ITAL0AJliD9pehLP472E0kaX895838BYEUKt6IHuCfXot9qih6s0gm6yukNA7Wy2DatZXagClEH7uJju3JHjmiMHF93Dfd5Sk5OHIOTLWDAl2As9JxBCamYGCy5tmMyYxgyiCDEvWqeA/LaTnZYXeLAKrNTwF4OnD4AZ0EvLOGd87k9mCDI1zaJhO9auHIdb7i284emD+UQ1VV+2WkxSGQEAAA==',
    'questions.json': '',
    'public/index.html': '',
    'public/style.css': '',
    'public/admin.js': '',
    'public/session.html': '',
    'public/protocol.html': '',
    'public/protocol.js': '',
    'public/protocol-print.html': '',
    'public/nauka.html': '',
    'public/nauka.js': '',
    'public/test.html': '',
    'public/test.js': '',
    'public/print.html': '',
    'public/report.html': '',
    'public/report.js': '',
}

DEST = os.path.expanduser('~/Desktop/psp-inspekcja')

for rel, enc in FILES.items():
    dest = os.path.join(DEST, rel)
    os.makedirs(os.path.dirname(dest), exist_ok=True)
    data = gzip.decompress(base64.b64decode(enc))
    with open(dest, 'wb') as f:
        f.write(data)
    print('written:', dest)

# Restart server
print('Restarting server...')
subprocess.run(['pkill', '-f', 'node server.js'], capture_output=True)
time.sleep(1)
log = open(os.path.join(DEST, 'server.log'), 'w')
subprocess.Popen(['node', 'server.js'], cwd=DEST, stdout=log, stderr=log)
print('Server restarted.')

os.chdir(DEST)
cmds = [
    ['git', 'add', '-A'],
    ['git', 'commit', '-m', 'deploy: fix auth URL params + protocol routes'],
    ['git', 'push', 'origin', 'main'],
]
for cmd in cmds:
    r = subprocess.run(cmd, capture_output=True, text=True)
    print(r.stdout.strip())
    if r.returncode != 0:
        print(r.stderr.strip())
        if 'nothing to commit' in r.stdout + r.stderr:
            print('Nothing new to commit.')
            break
        if cmd[1] == 'push':
            for wait in [2, 4, 8, 16]:
                time.sleep(wait)
                r2 = subprocess.run(cmd, capture_output=True, text=True)
                if r2.returncode == 0:
                    print(r2.stdout.strip())
                    break
                print(r2.stderr.strip())
print('Done.')
